module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output reg valid_out,
    output reg dout
);

    reg [1:0] cnt;
    reg [3:0] data;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 2'b00;
            data <= 4'b0000;
            valid_out <= 1'b0;
        end else begin
            if (cnt == 2'b11) begin
                cnt <= 2'b00;
                data <= d;
                valid_out <= 1'b1;
            end else begin
                cnt <= cnt + 1;
                data <= {data[2:0], data[3]};
                valid_out <= 1'b0;
            end
        end
    end

    assign dout = data[3];

endmodule
